INSERT INTO hdtm.g_tools VALUES ('nuclei_scan_osint_001', 'osint', 'osint-techint', 'Nuclei', 'Open Source', 'ProjectDiscovery', 'OSS', 'Scan target for vulnerabilities using Nuclei templates. Nuclei is a fast vulnerability scanner based on templates. It can detect CVEs, misconfigurations, and security issues. Supports filtering by severity, tags, and specific templates. Use for vulnerability scanning, security assessment, and detecting common security issues.', 'ProjectDiscovery', true, true, 'https://github.com/projectdiscovery/nuclei', false, '{vulnerability-scanning,cve-detection,security-assessment,template-based-scanning,osint,threat-intelligence,infrastructure}', 'Docker', 'Free', 'Community', 'https://docs.projectdiscovery.io/opensource/nuclei/usage', false, NULL, '{nuclei,vulnerability-scanning,cve,security-assessment,osint,threat-intelligence,infrastructure}', true, 4.8, true, true, 'system', '01K6ZS8CV61PECJAQBNW266EZ7', '2025-12-15 03:22:56.553441+00', '2026-01-07 19:54:55.087584+00', NULL, 'langchain_tool', 'shared.modules.tools.osint.nuclei_langchain', 'nuclei_scan', NULL);
INSERT INTO hdtm.g_tools VALUES ('youtube_transcripts_mcp_server_1767807456', 'osint', 'osint-digint', 'YouTube Transcripts MCP Server', 'OSINT Tool', 'https://hub.docker.com/u/mcp', 'OSS', 'Retrieves transcripts for given YouTube video URLs.', NULL, NULL, NULL, 'https://github.com/jkawamoto/mcp-youtube-transcript', NULL, NULL, 'Cloud', 'Free', 'Community', 'https://github.com/jkawamoto/mcp-youtube-transcript', true, '{"mcpServers": {"youtube_transcript": {"args": ["run", "-i", "--rm", "mcp/youtube-transcript"], "command": "docker"}}}', '{https://hub.docker.com/u/mcp,transcripts,retrieves,youtube,server,given,osint,video,tool,urls,mcp}', NULL, NULL, true, NULL, '01K6ZS8CV61PECJAQBNW266EZ7', '01K6ZS8CV61PECJAQBNW266EZ7', '2026-01-07 17:37:36.946803+00', NULL, NULL, 'mcp_server', NULL, NULL, NULL);
INSERT INTO hdtm.g_tools VALUES ('have_i_been_pwned_mcp_server_1767171485', 'cyberdefense', 'threat-intelligence', 'Have I Been Pwned MCP Server', 'Threat Intelligence Platform', 'https://github.com/darrenjrobinson/HIBP-MCP-Server', 'OSS', 'Have I Been Pwned MCP Server', NULL, NULL, NULL, 'https://github.com/darrenjrobinson/HIBP-MCP-Server', NULL, NULL, 'Cloud', 'Free', 'Community', 'https://github.com/darrenjrobinson/HIBP-MCP-Server', true, NULL, '{https://github.com/darrenjrobinson/hibp,intelligence,platform,server,threat,pwned,been,have,mcp}', NULL, NULL, true, NULL, '01K6ZS8CV61PECJAQBNW266EZ7', '01K6ZS8CV61PECJAQBNW266EZ7', '2025-12-31 08:58:05.285724+00', '2026-01-07 19:54:54.876946+00', NULL, 'mcp_server', NULL, NULL, NULL);
INSERT INTO hdtm.g_tools VALUES ('onionsearch_osint_001', 'osint', 'osint-darkint', 'OnionSearch MCP Server', 'Open Source', 'Hackerdogs', 'OSS', 'Scrape Dark Web search engines using OnionSearch tool. This tool searches across multiple .onion search engines to find URLs and content on the Dark Web. Requires Tor SOCKS5 proxy.', 'megadose', true, true, 'https://github.com/megadose/OnionSearch', false, '{dark-web-search,onion-search,osint,threat-intelligence}', 'Docker', 'Free', 'Community', 'https://github.com/megadose/OnionSearch', true, '{"mcpServers": {"onionsearch-mcp": {"args": ["run", "-i", "--rm", "-e", "MCP_TRANSPORT", "-e", "TOR_PROXY", "hackerdogs/onionsearch-mcp:latest"], "command": "docker", "env": {"MCP_TRANSPORT": "stdio", "TOR_PROXY": "127.0.0.1:9050"}}}}', '{onionsearch,dark-web,onion,search,osint,threat-intelligence,tor}', false, 4.0, true, true, 'system', '01K6ZS8CV61PECJAQBNW266EZ7', '2025-12-13 22:42:15.044784+00', '2026-03-15 00:00:00.000000+00', '{"TOR_PROXY": "tor-proxy:9050"}', 'mcp_server', NULL, NULL, NULL);
INSERT INTO hdtm.g_tools VALUES ('waybackurls_osint_001', 'osint', 'osint-domain-intel', 'Waybackurls', 'Open Source', 'Hackerdogs', 'OSS', 'Fetch URLs from Wayback Machine using waybackpy Python package. This tool queries the Wayback Machine to retrieve historical URLs for a given domain.', 'akamhy', true, true, 'https://github.com/akamhy/waybackpy', false, '{wayback-machine,historical-urls,osint,threat-intelligence,archive}', 'Local', 'Free', 'Community', 'https://github.com/akamhy/waybackpy', false, NULL, '{waybackurls,wayback-machine,archive,historical,urls,osint,threat-intelligence}', false, 4.2, true, true, 'system', '01K6ZS8CV61PECJAQBNW266EZ7', '2025-12-13 22:42:15.044784+00', '2025-12-25 09:52:15.997726+00', NULL, 'langchain_tool', 'shared.modules.tools.waybackurls_langchain', 'waybackurls_search', NULL);
