INSERT INTO hdtm.g_tools VALUES ('baidu_search_osint_001', 'osint', 'osint-domain-intel', 'Baidu Search', 'Open Source', 'Hackerdogs', 'OSS', 'Fetch Baidu search result pages and extract emails + hostnames for the target word/domain. Returns structured, LLM-friendly JSON. Implementation is inspired by theHarvester''s Baidu source but maintained by Hackerdogs.', 'Hackerdogs', true, true, NULL, false, '{search-engine,baidu,osint,domain-intelligence,subdomain-discovery,email-discovery}', 'Local', 'Free', 'Community', 'https://hackerdogs.ai', false, NULL, '{baidu,baidu-search,search,osint,domain,subdomain,emails,theharvester}', false, 4.0, true, true, 'system', '01KF434ZXYXTYNYDP6SKXSNG6W', '2025-12-29 06:18:21.051521+00', '2026-01-17 19:33:50.729295+00', '{"BAIDU_TIMEOUT": "20", "BAIDU_USER_AGENT": "Mozilla/5.0 (compatible; hackerdogs-core/1.0; +https://www.baidu.com/)"}', 'langchain_tool', 'shared.modules.tools.osint.baidusearch_langchain', 'baidu_search_web', NULL);
